text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트 통과를 전제로 금요일 15:00 KST를 공개 릴리스 목표로 한다.",
        "basis": "수요일 릴리스 제안에 대해 스모크 테스트 선행 필요 의견이 반영되어 최종 정리됨"
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토로 넘어간다.",
        "basis": "smoke-theme-pack.mjs에서 mismatch를 무시하자는 제안은 채택되지 않음"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경한다.",
        "result": "반려"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표",
        "note": "공개 릴리스의 최종 확정 목표가 아님"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차 검토",
        "note": "목요일까지 가능하면 검토하자는 의견은 있었지만 담당자가 지정되지 않아 확정 실행 항목으로 고정되지 않음"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있음"
      },
      {
        "risk": "README 설치 절차가 오래되었으면 릴리스 노트가 사용자를 오도할 수 있음"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": "목요일까지 가능하면",
      "status": "담당자 미지정",
      "source_certainty": "tentative"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "확정(시점 미정)",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 스모크 테스트 재실행 결과가 금요일 10:00 KST까지 공유되었는지 확인",
      "Doyun의 triage note가 금요일 12:00 KST까지 action_items.md에 작성되었는지 확인",
      "스모크 결과 이후 Hara의 tarball 경로 확인 결과를 추적",
      "README 설치 절차 검토 담당자 지정 여부를 확인",
      "최종 릴리스 승인 권한자와 릴리스 노트의 수요일 스트레치 목표 언급 여부를 결정해야 함"
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "명시되지 않은 담당자",
      "명시되지 않은 마감 시한"
    ]
  },
  "non_invention_rules": [
    "인라인 공개용 합성 픽스처에 있는 내용만 사용한다.",
    "확정 결정과 제안, 스트레치 목표, 리스크, 미해결 질문을 혼합하지 않는다.",
    "명시되지 않은 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "담당자와 기한은 원문에 있는 경우만 기록하고, 없으면 null 또는 미지정으로 둔다.",
    "내부 스트레치 목표를 확정 공개 일정처럼 표현하지 않는다.",
    "반려된 제안을 최종 방안처럼 서술하지 않는다."
  ]
}
